package com.enigma.familylinklite;

import android.Manifest;
import android.app.*;import android.app.admin.DevicePolicyManager;import android.app.usage.UsageStats;import android.app.usage.UsageStatsManager;import android.content.*;import android.content.pm.ApplicationInfo;import android.content.pm.PackageManager;import android.media.*;import android.net.wifi.WifiManager;import android.os.*;import android.provider.Settings;import android.text.format.Formatter;import android.view.*;import android.widget.*;import org.json.*;import java.io.*;import java.net.*;import java.nio.charset.StandardCharsets;import java.security.*;import java.text.*;import java.util.*;import javax.crypto.*;import javax.crypto.spec.*;

public class MainActivity extends Activity{
    static final int PORT=45454; LinearLayout root; String mode=""; byte[] key; String childIp=""; TextView log; volatile boolean alarm=false; ToneGenerator tone;
    public void onCreate(Bundle b){super.onCreate(b); getWindow().setSoftInputMode(WindowManager.LayoutParams.SOFT_INPUT_ADJUST_RESIZE); showStart();}
    TextView tv(String s,int sp){TextView v=new TextView(this);v.setText(s);v.setTextSize(sp);v.setPadding(18,12,18,12);return v;}
    Button btn(String s){Button b=new Button(this);b.setText(s);b.setAllCaps(false);return b;}
    EditText edit(String hint){EditText e=new EditText(this);e.setHint(hint);e.setSingleLine(false);e.setPadding(18,12,18,12);return e;}
    void base(String title){ScrollView sv=new ScrollView(this);root=new LinearLayout(this);root.setOrientation(LinearLayout.VERTICAL);root.setPadding(24,32,24,32);sv.addView(root);setContentView(sv);root.addView(tv(title,24));log=tv("",14);}
    void showStart(){base("FamilyLink Lite");root.addView(tv("Install this same APK on both devices. Choose Parent on your phone and Child on the tablet.",16));Button p=btn("Parent phone");Button c=btn("Child tablet");root.addView(p);root.addView(c);p.setOnClickListener(v->showParent());c.setOnClickListener(v->showChild());}
    void showChild(){mode="child";key=randomKey();base("Child tablet mode");String ip=getIp();String pair=ip+":"+PORT+":"+Base64.getEncoder().encodeToString(key);root.addView(tv("Pairing code. For now, copy this into the parent app. QR scanning can be added next.",16));TextView code=tv(pair,14);code.setTextIsSelectable(true);root.addView(code);Button usage=btn("Open Usage Access settings");root.addView(usage);usage.setOnClickListener(v->startActivity(new Intent(Settings.ACTION_USAGE_ACCESS_SETTINGS)));Button admin=btn("Enable device admin");root.addView(admin);admin.setOnClickListener(v->startActivity(new Intent(DevicePolicyManager.ACTION_ADD_DEVICE_ADMIN).putExtra(DevicePolicyManager.EXTRA_DEVICE_ADMIN,new ComponentName(this,AdminReceiver.class))));root.addView(log);startServer();}
    void showParent(){mode="parent";base("Parent phone mode");EditText pairing=edit("Paste child pairing code: ip:45454:key");root.addView(pairing);Button connect=btn("Save connection");root.addView(connect);connect.setOnClickListener(v->{try{String[] p=pairing.getText().toString().trim().split(":");childIp=p[0];key=Base64.getDecoder().decode(p[2]);toast("Saved");}catch(Exception e){toast("Invalid pairing code");}});EditText msg=edit("Message to child");root.addView(msg);Button send=btn("Send message");Button ping=btn("Ping / make sound");Button stop=btn("Stop ping");Button mute=btn("Mute media");Button vol30=btn("Set media volume 30%");Button vol70=btn("Set media volume 70%");Button usage=btn("Get app usage today");for(Button b:new Button[]{send,ping,stop,mute,vol30,vol70,usage})root.addView(b);send.setOnClickListener(v->cmd("message",msg.getText().toString()));ping.setOnClickListener(v->cmd("ping","start"));stop.setOnClickListener(v->cmd("ping","stop"));mute.setOnClickListener(v->cmd("volume","0"));vol30.setOnClickListener(v->cmd("volume","30"));vol70.setOnClickListener(v->cmd("volume","70"));usage.setOnClickListener(v->cmd("usage","today"));root.addView(log);}
    void startServer(){new Thread(()->{try(ServerSocket ss=new ServerSocket(PORT)){out("Server running on "+getIp()+":"+PORT);while(true){Socket s=ss.accept();BufferedReader r=new BufferedReader(new InputStreamReader(s.getInputStream()));String line=r.readLine();String json=decrypt(line);String resp=handle(new JSONObject(json));PrintWriter w=new PrintWriter(s.getOutputStream(),true);w.println(encrypt(resp));s.close();}}catch(Exception e){out("Server error: "+e.getMessage());}}).start();}
    String handle(JSONObject j)throws Exception{String type=j.optString("type"),value=j.optString("value");if(type.equals("message")){runOnUiThread(()->new AlertDialog.Builder(this).setTitle("Message from parent").setMessage(value).setPositiveButton("OK",null).show());return "Message shown";}if(type.equals("ping")){if(value.equals("start"))startAlarm();else stopAlarm();return "Ping "+value;}if(type.equals("volume")){setMediaVol(Integer.parseInt(value));return "Volume set to "+value+"%";}if(type.equals("usage")){return usageToday();}return "Unknown command";}
    void cmd(String type,String value){new Thread(()->{try{JSONObject j=new JSONObject();j.put("type",type);j.put("value",value);Socket s=new Socket();s.connect(new InetSocketAddress(childIp,PORT),2500);PrintWriter w=new PrintWriter(s.getOutputStream(),true);w.println(encrypt(j.toString()));BufferedReader r=new BufferedReader(new InputStreamReader(s.getInputStream()));String resp=decrypt(r.readLine());s.close();out(resp);}catch(Exception e){out("Command failed: "+e.getMessage());}}).start();}
    void setMediaVol(int percent){AudioManager a=(AudioManager)getSystemService(AUDIO_SERVICE);int max=a.getStreamMaxVolume(AudioManager.STREAM_MUSIC);int v=Math.max(0,Math.min(max,Math.round(max*percent/100f)));a.setStreamVolume(AudioManager.STREAM_MUSIC,v,0);}
    void startAlarm(){alarm=true;if(tone==null)tone=new ToneGenerator(AudioManager.STREAM_ALARM,100);new Thread(()->{while(alarm){tone.startTone(ToneGenerator.TONE_CDMA_ALERT_CALL_GUARD,700);try{Thread.sleep(900);}catch(Exception ignored){}}}).start();runOnUiThread(()->new AlertDialog.Builder(this).setTitle("Parent is pinging you").setMessage("Press OK to stop the sound.").setPositiveButton("OK",(d,w)->stopAlarm()).show());}
    void stopAlarm(){alarm=false;if(tone!=null)tone.stopTone();}
    String usageToday(){try{UsageStatsManager us=(UsageStatsManager)getSystemService(USAGE_STATS_SERVICE);Calendar c=Calendar.getInstance();c.set(Calendar.HOUR_OF_DAY,0);c.set(Calendar.MINUTE,0);c.set(Calendar.SECOND,0);List<UsageStats> stats=us.queryUsageStats(UsageStatsManager.INTERVAL_DAILY,c.getTimeInMillis(),System.currentTimeMillis());PackageManager pm=getPackageManager();stats.sort((a,b)->Long.compare(b.getTotalTimeInForeground(),a.getTotalTimeInForeground()));StringBuilder sb=new StringBuilder("Usage today:\n");int n=0;for(UsageStats st:stats){long mins=st.getTotalTimeInForeground()/60000;if(mins<1)continue;String name=st.getPackageName();try{ApplicationInfo ai=pm.getApplicationInfo(name,0);name=pm.getApplicationLabel(ai).toString();}catch(Exception ignored){}sb.append(name).append(": ").append(mins).append(" min\n");if(++n>=15)break;}return sb.toString();}catch(Exception e){return "Usage access not granted or unavailable: "+e.getMessage();}}
    byte[] randomKey(){byte[] b=new byte[32];new SecureRandom().nextBytes(b);return b;}
    String encrypt(String plain)throws Exception{byte[] iv=new byte[12];new SecureRandom().nextBytes(iv);Cipher c=Cipher.getInstance("AES/GCM/NoPadding");c.init(Cipher.ENCRYPT_MODE,new SecretKeySpec(key,"AES"),new GCMParameterSpec(128,iv));byte[] enc=c.doFinal(plain.getBytes(StandardCharsets.UTF_8));byte[] all=new byte[iv.length+enc.length];System.arraycopy(iv,0,all,0,iv.length);System.arraycopy(enc,0,all,iv.length,enc.length);return Base64.getEncoder().encodeToString(all);} 
    String decrypt(String data)throws Exception{byte[] all=Base64.getDecoder().decode(data);byte[] iv=Arrays.copyOfRange(all,0,12);byte[] enc=Arrays.copyOfRange(all,12,all.length);Cipher c=Cipher.getInstance("AES/GCM/NoPadding");c.init(Cipher.DECRYPT_MODE,new SecretKeySpec(key,"AES"),new GCMParameterSpec(128,iv));return new String(c.doFinal(enc),StandardCharsets.UTF_8);} 
    String getIp(){try{WifiManager wm=(WifiManager)getApplicationContext().getSystemService(WIFI_SERVICE);return Formatter.formatIpAddress(wm.getConnectionInfo().getIpAddress());}catch(Exception e){return "0.0.0.0";}}
    void out(String s){runOnUiThread(()->{log.setText(s+"\n\n"+log.getText());});}
    void toast(String s){Toast.makeText(this,s,Toast.LENGTH_SHORT).show();}
}
